class InColumnGroup extends HtmlTreeBuilderState {
    @Override
    public String toString() {
        return "InColumnGroup";
    }

    @Override
    protected boolean process(Token tk, HtmlTreeBuilder builder) {
        if (isWhitespace(tk)) {
            builder.insert(tk.asCharacter());
            return true;
        }
        switch (tk.typ) {
            case CommentType:
                builder.insert(tk.asComment());
                break;
            case DoctypeType:
                builder.error(this);
                break;
            case StartTagType: {
                StartTag startTag = tk.asStartTag();
                String normalName = startTag.normalName();
                switch (normalName) {
                    case "html":
                        return builder.process(tk, InBody);
                    case "col":
                        builder.insertEmpty(startTag);
                        break;
                    case "template":
                        builder.process(tk, InHead);
                        break;
                    default:
                        return anythingElse(tk, builder);
                }
                break;
            }
            case EndTagType: {
                EndTag endTag = tk.asEndTag();
                String name = endTag.normalName();
                switch (name) {
                    case "colgroup":
                        if (!builder.currentElementIs(name)) {
                            builder.error(this);
                            return false;
                        } else {
                            builder.pop();
                            builder.transition(InTable);
                        }
                        break;
                    case "template":
                        builder.process(tk, InHead);
                        break;
                    default:
                        return anythingElse(tk, builder);
                }
                break;
            }
            case EOFType:
                if (builder.currentElementIs("html")) {
                    return true; // stop parsing; frag case
                } else {
                    return anythingElse(tk, builder);
                }
            default:
                return anythingElse(tk, builder);
        }
        return true;
    }

    private boolean anythingElse(Token tk, HtmlTreeBuilder builder) {
        if (!builder.currentElementIs("colgroup")) {
            builder.error(this);
            return false;
        }
        builder.pop();
        builder.transition(InTable);
        builder.process(tk);
        return true;
    }
}

