                    return true // stop parsing; frag case
                } else {
                    return anythingElse(tk, builder)
                }
            case _ => return anythingElse(tk, builder)
        }
        return true
    }

    private func anythingElse(tk: Token, builder: HtmlTreeBuilder): Bool {
