import java.util.*;

public class DataCollection<C extends DataFields<T> & Collection<T>, T extends DataFields<T>>
    extends Data
    implements Collection<Data> {

    private final C data;

    public DataCollection(C data) {
        this.data = data;
    }

    @Override
    public Iterator<Data> iterator() {
        return new DataCollectionIterator<>(data.iterator());
    }

    @Override
    public int size() {
        return (int) data.size(); // Assuming DataFields.size() returns long, cast to int for Collection contract
    }

    @Override
    public boolean isEmpty() {
        return data.isEmpty();
    }

    @Override
    public String toString() {
        StringBuilder b = new StringBuilder("[");
        boolean first = true;
        for (T d : data) {
            if (!first) {
                b.append(',');
            }
            b.append(d.toData().toString());
            first = false;
        }
        b.append(']');
        return b.toString();
    }

    // Static utility methods — note: Java has no top-level static methods in generic classes like this,
    // so we keep them as static methods in the same class.
    public static <C extends DataFields<T> & Collection<T>, T extends DataFields<T>>
        Optional<Data> tryParse(String s) {
        return Optional.empty();
    }

    public static <C extends DataFields<T> & Collection<T>, T extends DataFields<T>>
        Data parse(String s) {
        throw new DataParsableException(s + " cannot be parsed to " +
            DataCollection.class.getTypeName());
    }
}

