class DataCollectionIterator<T extends DataFields<T>> implements Iterator<Data> {
    private final Iterator<T> inner;

    public DataCollectionIterator(Iterator<T> inner) {
        this.inner = inner;
    }

    @Override
    public boolean hasNext() {
