import java.util.concurrent.atomic.AtomicBoolean;

interface NodeFilter {
    // Assuming FilterResult is an enum with STOP and CONTINUE
}

enum FilterResult {
    STOP,
    CONTINUE
}

// Assuming Node and TextNode are defined elsewhere; we'll define minimal stubs for compilation
abstract class Node {
}

class TextNode extends Node {
    abstract boolean isBlank();
}

class HasTextNodeFilter implements NodeFilter {
    private final AtomicBoolean hasText;

    public HasTextNodeFilter(AtomicBoolean hasText) {
        this.hasText = hasText;
    }

    public FilterResult head(Node node, long depth) {
        if (node instanceof TextNode) {
            TextNode textNode = (TextNode) node;
            if (!textNode.isBlank()) {
                hasText.set(true);
                return FilterResult.STOP;
            }
        }
