import java.util.*;
import java.util.concurrent.locks.ReentrantLock;

public class Span {
    public final String traceId;
    public final String spanId;
    public final Optional<String> parentSpanId;
    public final String operationName;
    public final long startTime;
    private Optional<Long> endTime;
    private final Map<String, String> tags;
    private final List<SpanLog> logs;
    private final ReentrantLock mutex;
    private volatile boolean finished;

    public Span(String traceId, String spanId, Optional<String> parentSpanId, String operationName) {
        this.traceId = traceId;
        this.spanId = spanId;
        this.parentSpanId = parentSpanId;
        this.operationName = operationName;
        this.startTime = System.currentTimeMillis();
        this.endTime = Optional.empty();
        this.tags = new HashMap<>();
        this.logs = new ArrayList<>();
        this.mutex = new ReentrantLock();
        this.finished = false;
    }

    /**
     * 设置标签
     */
    public Span setTag(String key, String value) {
        mutex.lock();
        try {
            if (!finished) {
                tags.put(key, value);
            }
        } finally {
            mutex.unlock();
        }
        return this;
    }

    /**
     * 记录日志
     */
    public Span log(String message) {
        mutex.lock();
        try {
            if (!finished) {
                logs.add(new SpanLog(System.currentTimeMillis(), message));
            }
        } finally {
            mutex.unlock();
        }
        return this;
    }

    /**
     * 记录带字段的日志
     */
    public Span logWithFields(Map<String, String> fields) {
        mutex.lock();
        try {
            if (!finished) {
                // 简化实现：将字段转换为字符串消息
                logs.add(new SpanLog(System.currentTimeMillis(), "fields_logged"));
            }
        } finally {
            mutex.unlock();
        }
        return this;
    }

    /**
     * 完成跨度
     */
    public void finish() {
        mutex.lock();
        try {
            if (!finished) {
                endTime = Optional.of(System.currentTimeMillis());
                finished = true;
            }
        } finally {
            mutex.unlock();
        }
    }

    /**
     * 获取持续时间（毫秒）
     */
    public Optional<Long> getDuration() {
        mutex.lock();
        try {
            return endTime.map(end -> end - startTime);
        } finally {
            mutex.unlock();
        }
    }

    /**
     * 是否已完成
     */
    public boolean isFinished() {
        mutex.lock();
        try {
            return finished;
        } finally {
            mutex.unlock();
        }
    }

    /**
     * 获取标签
     */
    public Map<String, String> getTags() {
        mutex.lock();
        try {
            return new HashMap<>(tags);
        } finally {
            mutex.unlock();
        }
    }

    /**
     * 打印跨度信息
     */
    public void printSpanInfo() {
        mutex.lock();
        try {
            System.out.println("🔍 Span信息:");
            System.out.println("   TraceId: " + traceId);
            System.out.println("   SpanId: " + spanId);
            if (parentSpanId.isPresent()) {
                System.out.println("   ParentSpanId: " + parentSpanId.get());
            } else {
                System.out.println("   ParentSpanId: <根跨度>");
            }
            System.out.println("   操作名称: " + operationName);
            System.out.println("   开始时间: " + startTime);
            if (endTime.isPresent()) {
                long end = endTime.get();
                System.out.println("   结束时间: " + end);
                System.out.println("   持续时间: " + (end - startTime) + "ms");
            } else {
                System.out.println("   状态: 进行中");
            }
            System.out.println("   标签数量: " + tags.size());
            System.out.println("   日志数量: " + logs.size());
        } finally {
            mutex.unlock();
        }
    }
}

