public SurfaceCore createLinearGradientBrush(
        LinearGradientBrush ref,
        Color startColor,
        Color endColor,
        FPoint startPoint,
        FPoint endPoint,
        ColorPct[] midPctColor,
        boolean useGammaCorrection) {
    if (midPctColor == null) {
        midPctColor = new ColorPct[0];
    }

    if (!isValid()) {
        throw new RuntimeException(rgfErrorCpluapluaObjNotExist);
    }
    ref.release();

    if (midPctColor.length > 0) {
        int len = midPctColor.length;
        // Allocate native memory for color array (ColorF struct)
        long colorArrayPtr = LibC.malloc(len * ColorF.SIZE_IN_BYTES);
        // Allocate native memory for percentage array (float32)
        long pointArrayPtr = LibC.malloc(len * 4); // float32 = 4 bytes

        for (int i = 0; i < len; i++) {
            ColorF colorStruct = midPctColor[i].color.toStruct();
            // Write ColorF struct to native memory
            LibC.writeColorF(colorArrayPtr + (long) i * ColorF.SIZE_IN_BYTES, colorStruct);
            // Write float32 percentage
            LibC.writeFloat32(pointArrayPtr + (long) i * 4, midPctColor[i].percentage);
        }

        ref.objPtr = rApiDctClassCreateLinearGradientBrush(
                objPtr,
                startColor.toStruct(),
                endColor.toStruct(),
                startPoint.toStruct(),
                endPoint.toStruct(),
                colorArrayPtr,
                pointArrayPtr,
                len,
                useGammaCorrection
        );

        LibC.free(colorArrayPtr);
        LibC.free(pointArrayPtr);
    } else {
        ref.objPtr = rApiDctClassCreateLinearGradientBrush(
                objPtr,
                startColor.toStruct(),
                endColor.toStruct(),
                startPoint.toStruct(),
                endPoint.toStruct(),
                0L, // null pointer for colorArray
                0L, // null pointer for pointArray
                0,
                useGammaCorrection
        );
    }

    return this;
}

