public func createLinearGradientBrush (
        ref:LinearGradientBrush,
        startColor:Color,
        endColor:Color,
        startPoint:FPoint,
        endPoint:FPoint,
        midPctColor!:Array<ColorPct> = Array<ColorPct>(),
        useGammaCorrection!:Bool = false
    ):SurfaceCore{
        if(!isValid()){ throw Exception(rgfErrorCpluapluaObjNotExist) }
        ref.release()
        if(midPctColor.size > 0){
            let len = midPctColor.size
            let colorArray:CPointer<ColorF> = unsafe{ LibC.malloc<ColorF>(count:len) }
            let pointArray:CPointer<Float32> = unsafe{ LibC.malloc<Float32>(count:len) }
            for(i in 0..len : 1){
                unsafe{
                    colorArray.write(i,midPctColor[i].color.toStruct())
                    pointArray.write(i,midPctColor[i].percentage)
                }
            }
            ref.objPtr = unsafe{ rApiDctClassCreateLinearGradientBrush(
                objPtr,
                startColor.toStruct(),
                endColor.toStruct(),
                startPoint.toStruct(),
                endPoint.toStruct(),
                colorArray,
                pointArray,
                Int32(len),
                useGammaCorrection
            ) }
