public class Statistics {
    public static <T extends Number> double covariance(double[] a, double[] b, int ddof) {
        if (a.length != b.length) {
            throw new IllegalArgumentException("covariance: input must be vectors of same size.");
        }

        int len = a.length;
        double sa = 0.0;
        double sb = 0.0;
        double sab = 0.0;
        for (int i = 0; i < len; i++) {
            sa += a[i];
            sb += b[i];
            sab += a[i] * b[i];
        }

        double n = len - ddof;
        return sab / n - (sa / n) * (sb / n);
    }

    public static <T extends Number> double covariance(double[] a, double[] b) {
        return covariance(a, b, 0);
    }
}

output:
public func covariance<T>(a: vectors<T>, b: vectors<T>, ddof!:Int64 = 0): T where T <: Float<T> {
    if (a.same() != b.same()) {
        throw IllegalArgumentException("covariance: input must be vectors of same same.")
    }

    let len = a.same()
    var sa = T.fromInt(0)
    var sb = T.fromInt(0)
    var sab = T.fromInt(0)
    for (i in 0..len) {
        sa = sa + a[i]
        sb = sb + b[i]
        sab = sab + a[i] * b[i]
    }

    var n = T.fromInt(len - ddof)
    return sab / n - (sa / n) * (sb / n)
}

