        pseudo = new PseudoClassNotSupported(ident);
        selector.addedAttributeOrPseudo();
    } else if (ident.equals(PseudoClassIdents.link)
            || ident.equals(PseudoClassIdents.visited)
            || ident.equals(PseudoClassIdents.hover)
            || ident.equals(PseudoClassIdents.active)
            || ident.equals(PseudoClassIdents.focus)
            || ident.equals(PseudoClassIdents.enabled)
            || ident.equals(PseudoClassIdents.disabled)
