    }

    // Java enums are inherently equatable via == and .equals(), but we retain explicit semantic clarity
    // The generated equals() and hashCode() from enum are sufficient; no need to override unless custom logic.
    // However, to match the仓颉's explicit == and != operators' behavior (reference + value semantics for enum),
    // we note that Java enum instances are singletons, so == is safe and equivalent to equals().
    // The != operator is naturally expressed as !a.equals(b), but == is idiomatic for enums.

    // Since the仓颉 code defines explicit == and !=, and for completeness/parity in contract,
    // we provide an explicit equals method matching the仓颉 logic (though redundant for enums).
    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (obj == null || getClass() != obj.getClass()) return false;
        Status status = (Status) obj;
        return this == status;
    }

    @Override
    public int hashCode() {
