public class CryptoClient {
    private final String host;
    private final int port;
    private final HttpClient httpClient; // Assume HttpClient is a custom or adapted HTTP client

    public CryptoClient(String host, int port, HttpClient httpClient) {
        this.host = host;
        this.port = port;
        this.httpClient = httpClient;
    }

    public InputStream encrypt(
            String storeName,
            InputStream stream,
            String keyName,
            EncryptOptions encryptOptions) throws IllegalArgumentException, IOException, DaprException {
        if (storeName == null || storeName.trim().isEmpty()) {
            throw new IllegalArgumentException("empty storeName");
        }

        if (keyName == null || keyName.trim().isEmpty()) {
            throw new IllegalArgumentException("empty keyName");
        }

        String url = "http://" + host + ":" + port + "/v1.0-alpha1/crypto/" + storeName + "/encrypt";

        Request request = Request.builder()
                .url(url)
                .put(new StreamRequestBody(stream))
                .header("dapr-key-name", keyName)
                .header("dapr-key-wrap-algorithm", encryptOptions.getKeyWrapAlgorithm().toString())
                .header("dapr-omit-decryption-key-name",
                        encryptOptions.getOmitDecryptionKeyName() != null
                                ? encryptOptions.getOmitDecryptionKeyName().toString()
                                : "")
                .header("dapr-decryption-key-name",
                        encryptOptions.getDecryptionKeyName() != null
                                ? encryptOptions.getDecryptionKeyName()
                                : "")
                .header("dapr-data-encryption-cipher",
                        encryptOptions.getDataEncryptionCipher() != null
                                ? encryptOptions.getDataEncryptionCipher().toString()
                                : "")
                .build();

        Response res = httpClient.newCall(request).execute();

        int statusCode = res.getCode();
        if (statusCode == 200) {
            try {
                return res.getBody().getOrThrow().getSource().toInputStream();
            } catch (Exception e) {
                throw new IOException("Failed to convert response body to InputStream", e);
            }
        } else {
            throw res.getAs(DaprException.class);
        }
    }
}

