public void callCreated(long hwnd, int x, int y, int nWidth, int nHeight) {
    Optional<WinCore> objOpt = this.getObj();
    if (objOpt.isPresent()) {
        WinCore obj = objOpt.get();
        // 判断当前窗口是否为主窗口
        if (rwIsMainWin(obj)) {
            mainWinHwnd = hwnd;
        }
        // Try to call bindCreated; if it returns non-null, do nothing; otherwise fall back to created
        Long hwndUIntNative = Long.valueOf(hwnd);
        if (obj.bindCreated != null && obj.bindCreated.apply(hwndUIntNative, x, y, nWidth, nHeight) != null) {
            // bindCreated succeeded, no further action needed
        } else {
            obj.created(hwndUIntNative, x, y, nWidth, nHeight);
        }
        // 就绪后开始定时渲染
        if (obj.refreshInterval.compareTo(Duration.ZERO) > 0 && obj.autoRefresh == null) {
            // 设备资源创建完成，则透明窗口预备开始定时刷新
            obj.autoRefresh = RTimer.repeat(
                Duration.ZERO,
                obj.refreshInterval,
                () -> {
                    if (obj.allowRendering.get()) {
                        obj.draw();
                    }
                },
                CatchupStyle.SKIP,
                () -> obj.autoRefresh = null
            );
        }
    }
}

