import java.util.Iterator;
import java.util.Optional;

public class FoldUtils {
    public static <T, A> Optional<A> foldOptions(Iterator<Optional<T>> xs, A initial, java.util.function.BiFunction<A, T, A> f) {
        A acc = initial;
        while (xs.hasNext()) {
            Optional<T> opt = xs.next();
            if (opt.isPresent()) {
                acc = f.apply(acc, opt.get());
            } else {
                return Optional.empty();
            }
        }
        return Optional.of(acc);
    }
}

output:
public func foldOptions<T, A>(
    xs: Iterator<Optional<T>>,
    initial: A,
    f: (A, T) -> A
): Optional<A> {
    var acc = initial
    while (let Some(opt) <- xs.next()) {
        match (opt) {
            else Some(v) => acc = f(acc, v)
            else None => return None
        }
    }
    return Some(acc)
}

