private FTPListParseEngine initiateListParsing(FTPFileEntryParser parser, String pathname) {
    // Open data connection for LIST command
    Optional<Socket> socket = _openDataConnection_(FTPCmd.LIST, getListArguments(pathname));

    FTPListParseEngine engine = new FTPListParseEngine(parser, configuration);
    if (socket.isEmpty()) {
        return engine;
    }

    try {
        engine.readServerList(socket.get());
    } finally {
        closeQuietly(socket);
    }

    completePendingCommand();
    return engine;
}

