import java.util.Objects;

public class AddrPort {
    private final String addr;
    private final int port; // UInt16 maps to int in Java (unsigned not natively supported, but range fits in int)

    public AddrPort(String addr, int port) {
        if (port < 0 || port > 65535) {
            throw new IllegalArgumentException("port must be between 0 and 65535");
        }
        this.addr = addr;
        this.port = port;
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (obj == null || getClass() != obj.getClass()) return false;
        AddrPort addrPort = (AddrPort) obj;
        return port == addrPort.port && Objects.equals(addr, addrPort.addr);
    }

    @Override
    public int hashCode() {
        return Objects.hash(addr, port);
    }

    @Override
    public String toString() {
        return addr + ":" + port;
    }
}

