public class StereoTopBand {
    public static void L3_stereo_top_band(double[] right, long[] sfb, long nbands, long[] max_band) {
        long i = 0;
        long k = 0;
        max_band[0] = -1;
        max_band[1] = -1;
        max_band[2] = -1;
        long off = 0;
        while (i < nbands) {
            k = 0;
            while (k < sfb[(int) i]) {
                // Check two consecutive elements: off+k and off+k+1
                if (!(right[(int) (off + k)] == 0.0 && right[(int) (off + k + 1)] == 0.0)) {
                    max_band[(int) (i % 3)] = i;
                    break;
                }
                k += 2;
            }
            off += sfb[(int) i];
            i++;
        }
    }
}

