    max_band[0] = -1
    max_band[1] = -1
    max_band[2] = -1
    var off: Int64 = 0
    while (i < nbands) {
        k = 0
        while (k < sfb[i]) {
            if (!(right[off + k] == 0.0 && right[off + k + 1] == 0.0)) {
                max_band[i % 3] = i
                break
            }
            k = k + 2
        }
        off = off + sfb[i]
        i = i + 1
    }
}

