    // Add all nodes between the opening bracket and now (closing bracket) as child nodes of the link
    Node n = opener.bracketNode.getNext();
    while (n != null) {
        Node n1 = n;
        n = n1.getNext();
        wrapperNode.appendChild(n1);
    }

    if (includeSourceSpans) {
        SourcePosition startPosition = includeMarker && opener.markerPosition.isPresent()
                ? opener.markerPosition.get()
                : opener.bracketPosition;
        wrapperNode.setSourceSpans(
                _scanner.getSource(startPosition, _scanner.position()).getSourceSpans());
    }

    // Process delimiters such as emphasis inside link/image
    processDelimiters(opener.previousDelimiter);
    mergeChildTextNodes(wrapperNode);
    // We don't need the corresponding text node anymore, we turned it into a link/image node
    if (includeMarker && opener.markerNode.isPresent()) {
        opener.markerNode.get().unlink();
    }
    opener.bracketNode.unlink();
    removeLastBracket();

    // Links within links are not allowed. We found this link, so there can be no other link around it.
    if (opener.markerNode.isEmpty()) {
        Optional<BracketV2> bracket = lastBracket;
        while (bracket.isPresent()) {
            BracketV2 _bracket = bracket.get();
            if (_bracket.markerNode.isEmpty()) {
                // Disallow link opener. It will still get matched, but will not result in a link.
                _bracket.allowed = false;
            }
            bracket = _bracket.previous;
        }
    }

    return wrapperNode;
}

