        node.setSourceSpans(_scanner.getSource(startPosition, _scanner.position()).getSourceSpans());
    }

    removeLastBracket();

    // Remove nodes that we added since the opener, because we're replacing them
    Node n = includeMarker && opener.markerNode.isPresent()
            ? opener.markerNode.get()
            : opener.bracketNode;
    while (n != null) {
        Node next = n.getNext();
        n.unlink();
        n = next;
    }
