public static void appendQuotedString(StringBuilder target, String key) {
    target.append('"');
    for (int i = 0; i < key.length(); i++) {
        char c = key.charAt(i);
        switch (c) {
            case '\n':
                target.append("%0A");
                break;
            case '\r':
                target.append("%0D");
                break;
            case '"':
                target.append("%22");
                break;
            default:
                target.append(c);
                break;
        }
    }
    target.append('"');
}

output:
func appendQuotedString(target: StringBuilder, key: String): Unit {
    target.append('"')
    for (i in key) {
        match (i) {
            case b'\n' => target.append("%0A")
            case b'\r' => target.append("%0D")
            case b'"' => target.append("%22")
            case _ => target.append(i)
        }
    }
    target.append('"')
}

