        let scaleX = bounds.width / texSize.width
        let scaleY = bounds.height / texSize.height
        let scale = if (scaleX > scaleY) { scaleX } else { scaleY }

        let width = texSize.width * scale
        let height = texSize.height * scale
        let x = bounds.x + (bounds.width - width) / 2.0
        let y = bounds.y + (bounds.height - height) / 2.0

        return Rect(x, y, width, height)
    }
}

