public func kSmallest<T>(xs: Iterator<T>, k: Int64, less: (T, T) -> Bool): ArrayList<T> {
    if (k <= 0) {
        return ArrayList<T>()
    }

    // 使用 max-heap 维护 k 个最小元素
    // max-heap 的堆顶是当前 k 个元素中最大的
    let heap = maxHeap<T>(less)

    while (let Some(x) <- xs.next()) {
        if (heap.size() < k) {
            heap.push(x)
        } else {
            // 如果当前元素比堆顶小，替换堆顶
            match (heap.peek()) {
                case Some(top) =>
                    if (less(x, top)) {
                        let _ = heap.replaceTop(x)
                    }
                case None => ()
            }
        }
    }

    // 从堆中提取元素并排序
    let result = ArrayList<T>()
    while (let Some(x) <- heap.pop()) {
        result.add(x)
    }
    // 反转得到升序（因为 max-heap pop 出来是降序）
    reverse(result)
    return result
}

