/**
 * Reads a Float64 value from a C buffer, checking null indicator first.
 *
 * @param buffer Pointer to the memory location containing the Float64 value
 * @param isNull Pointer to a boolean indicating whether the value is NULL
 * @return The Float64 value if not null; null otherwise
 */
public static Double getFloat64(long buffer, long isNull) {
    // Simulate CPointer<Bool>.read() — read a single byte as boolean (0 = false, non-zero = true)
    boolean isNullValue = unsafeGetByte(isNull) != 0;

    if (isNullValue) {
        return null;
    } else {
        // Read 8-byte double-precision float from buffer address
        return unsafeGetDouble(buffer);
    }
}

// Helper methods to simulate low-level memory access (e.g., via Unsafe or VarHandle in real usage)
// Note: In production, these would use java.lang.invoke.VarHandle or sun.misc.Unsafe
private static native byte unsafeGetByte(long address);
private static native double unsafeGetDouble(long address);

