import java.util.*;

public class AclGetUserResponseBuilder implements ResponseBuilder<HashMap<String, Object>> {
    @Override
    public HashMap<String, Object> build(RedisMessage redisMessage) {
        // Handle null bulk string (nil reply)
        if (redisMessage instanceof BulkStringRedisMessage) {
            BulkStringRedisMessage stringMessage = (BulkStringRedisMessage) redisMessage;
            if (stringMessage.isNull()) {
                return null;
            } else {
                throw new RedisException("Incompatible type, not null/nil BULK_STRINGS is not the expected type");
            }
        } else if (redisMessage instanceof NullRedisMessage) {
            return null;
        }

        // Parse list of key-value pairs
        List<KeyValueRedisMessage> keyValues = ResponseBuilderFactory.listOfKeyValueBuilder.build(redisMessage);
        HashMap<String, Object> userInfo = new HashMap<>();

        for (KeyValueRedisMessage keyValue : keyValues) {
            RedisMessage keyMessage = keyValue.getKey();
            RedisMessage valueMessage = keyValue.getValue();
            buildAclGetUserResponse(keyMessage, valueMessage, userInfo);
        }

        return userInfo;
    }

    /**
     * 解析ACL GETUSER username命令的响应
     */
    private void buildAclGetUserResponse(
            RedisMessage keyMessage,
            RedisMessage valueMessage,
            HashMap<String, Object> userInfo) {
        String key = ResponseBuilderFactory.stringBuilder.build(keyMessage);

        switch (key) {
            case "flags":
            case "passwords":
                List<String> stringList = ResponseBuilderFactory.listOfStringBuilder.build(valueMessage);
                userInfo.put(key, stringList);
                break;
            case "commands":
                String stringValue = ResponseBuilderFactory.stringBuilder.build(valueMessage);
                userInfo.put(key, stringValue);
                break;
            case "keys":
            case "channels":
                if (valueMessage instanceof ArraysRedisMessage) {
                    List<String> arrayValue = ResponseBuilderFactory.listOfStringBuilder.build((ArraysRedisMessage) valueMessage);
                    userInfo.put(key, arrayValue);
                } else if (valueMessage instanceof BulkStringRedisMessage) {
                    // Redis 7.0.0: space-separated string
                    String spaceSeparated = ResponseBuilderFactory.stringBuilder.build((BulkStringRedisMessage) valueMessage);
                    String[] parts = spaceSeparated.split("\\s+");
                    if (parts.length > 0) {
                        List<String> list = new ArrayList<>();
                        Collections.addAll(list, parts);
                        userInfo.put(key, list);
                    } else {
                        userInfo.put(key, spaceSeparated);
                    }
                } else {
                    throw new RedisException("Incompatible type, " + valueMessage.getType() + " is not the expected type");
                }
                break;
            case "selectors":
                if (valueMessage instanceof ArraysRedisMessage) {
                    ArraysRedisMessage arrayMessage = (ArraysRedisMessage) valueMessage;
                    List<HashMap<String, String>> selectors = new ArrayList<>();
                    List<RedisMessage> children = arrayMessage.getValue();
                    if (children != null) {
                        for (RedisMessage child : children) {
                            HashMap<String, String> selectorEntry = ResponseBuilderFactory.stringToStringMapBuilder.build(child);
                            selectors.add(selectorEntry);
                        }
                    }
                    userInfo.put(key, selectors);
                } else {
                    throw new RedisException("Incompatible type, " + valueMessage.getType() + " is not the expected type for 'selectors'");
                }
                break;
            default:
                // Future version extension keys — ignore silently
                break;
        }
    }
}

