import java.util.ArrayList;
import java.util.List;

public class ListOfAnyResponseBuilder implements ResponseBuilder<ArrayList<Object>> {

    @Override
    public ArrayList<Object> build(RedisMessage message) {
        if (message instanceof ArraysRedisMessage arraysMessage) {
            if (arraysMessage.isNull() || arraysMessage.getSize() == 0) {
                return new ArrayList<>();
            }
            List<RedisMessage> children = arraysMessage.getValue();
            ArrayList<Object> results = new ArrayList<>();
            if (children != null) {
                processChildren(children, results);
            }
            return results;
        } else if (message instanceof SetRedisMessage setMsg) {
            if (setMsg.getSize() == 0) {
                return new ArrayList<>();
            }
            List<RedisMessage> children = setMsg.getValue();
            ArrayList<Object> results = new ArrayList<>();
            processChildren(children, results);
            return results;
        } else if (message instanceof ErrorRedisMessage errorMsg) {
            throw new RedisException(errorMsg.getValue());
        }

        throw new RedisException("Unsupported message type: " + message.getType());
    }

    private void processChildren(List<RedisMessage> children, ArrayList<Object> results) {
        for (RedisMessage child : children) {
            Object anyResult = buildToAny(child);
            results.add(anyResult);
        }
    }

    /**
     * 将RedisMessage解析为任意类型
     */
    public static Object buildToAny(RedisMessage redisMessage) {
        if (redisMessage instanceof IntegerRedisMessage integerMessage) {
            return integerMessage.getValue();
        } else if (redisMessage instanceof StringRedisMessage stringMessage) {
            return stringMessage.getValue();
        } else if (redisMessage instanceof BulkStringRedisMessage bulkStringMessage) {
            String value = bulkStringMessage.getStringValue();
            if (value != null) {
                return value;
            } else {
                throw new RedisException("Null value");
            }
        } else if (redisMessage instanceof VerbatimRedisMessage verbatimMessage) {
            return verbatimMessage.getStringContent();
        } else if (redisMessage instanceof BooleanRedisMessage booleanMessage) {
            return booleanMessage.getValue();
        } else if (redisMessage instanceof DoubleRedisMessage doubleMessage) {
            return doubleMessage.getValue();
        } else if (redisMessage instanceof BigNumberRedisMessage bigNumberMessage) {
            return bigNumberMessage.getValue();
        } else if (redisMessage instanceof ArraysRedisMessage arraysMessage) {
            return ResponseBuilderFactory.listOfAnyBuilder.build(arraysMessage);
        } else if (redisMessage instanceof MapRedisMessage mapMessage) {
            return ResponseBuilderFactory.mapOfAnyBuilder.build(mapMessage);
        } else if (redisMessage instanceof SetRedisMessage setMsg) {
            // 将SetRedisMessage也转换为List
            return ResponseBuilderFactory.listOfAnyBuilder.build(setMsg);
        } else if (redisMessage instanceof NullRedisMessage) {
            throw new RedisException("Null value");
        } else if (redisMessage instanceof BulkErrorRedisMessage bulkErrorMsg) {
            throw new RedisException(bulkErrorMsg.getValue());
        } else if (redisMessage instanceof ErrorRedisMessage errorMsg) {
            throw new RedisException(errorMsg.getValue());
        }

        throw new RedisException("Incompatible type, " + redisMessage.getType() + " is not the expected type");
    }
}

