/**
 * 跟踪迭代器，用于在遍历时输出调试信息。
 *
 * @param <T> 迭代元素类型，需支持字符串转换（通过 toString()）
 */
public class TraceIterator<T> implements Iterator<T> {
    private final Iterator<T> base;
    private final String name;
    private final TraceConfig config;
    private long index;

    /**
     * 创建跟踪迭代器。
     *
     * @param base   底层迭代器
     * @param name   跟踪器名称
     * @param config 跟踪配置
     */
    public TraceIterator(Iterator<T> base, String name, TraceConfig config) {
        this.base = base;
        this.name = name;
        this.config = config;
        this.index = 0;
    }

    @Override
    public boolean hasNext() {
        return base.hasNext();
    }

    @Override
    public T next() {
        T value = base.next();

        if (config.isEnabled()) {
            String msg = config.getPrefix() + " " + name + "[" + index + "]: " + value;
            config.output(msg);
            index++;
        } else {
            index++;
        }

        return value;
    }

    /**
     * 注意：此实现不支持 remove() 操作，调用时抛出 UnsupportedOperationException。
     */
    @Override
    public void remove() {
        throw new UnsupportedOperationException("remove() is not supported in TraceIterator");
    }
}

