                    let msg = "${this.config.prefix} ${this.name}[${this.index}]: ${value}"
                    this.config.output(msg)
                    this.index += 1
                case None =>
                    let msg = "${this.config.prefix} ${this.name}: end of iterator (${this.index} elements)"
                    this.config.output(msg)
            }
        } else {
            match (result) {
                case Some(_) => this.index += 1
                case None => ()
            }
        }

        return result
    }
}

