import java.util.*;

/**
 * 绑定列表，支持监听列表变更事件。
 * @param <T> 列表元素类型
 */
public class BindList<T> {
    private final ArrayList<T> _items;
    private final ArrayList<ListListener<T>> _listeners;

    /**
     * 创建绑定列表
     */
    public BindList() {
        _items = new ArrayList<>();
        _listeners = new ArrayList<>();
    }

    /**
     * 创建带初始项目的绑定列表
     */
    public BindList(T[] items) {
        _items = new ArrayList<>();
        if (items != null) {
            Collections.addAll(_items, items);
        }
        _listeners = new ArrayList<>();
    }

    /**
     * 获取项目数量
     */
    public long count() {
        return _items.size();
    }

    /**
     * 是否为空
     */
    public boolean isEmpty() {
        return _items.isEmpty();
    }

    /**
     * 获取项目
     */
    public T get(long index) {
        if (index < 0 || index >= _items.size()) {
            throw new IndexOutOfBoundsException("Index: " + index + ", Size: " + _items.size());
        }
        return _items.get((int) index);
    }

    /**
     * 设置项目
     */
    public void set(long index, T value) {
        if (index < 0 || index >= _items.size()) {
            throw new IndexOutOfBoundsException("Index: " + index + ", Size: " + _items.size());
        }
        _items.set((int) index, value);
        notifyListeners(new ListChange<>(ListChangeType.UPDATED, index, Optional.of(value)));
    }

    /**
     * 添加项目
     */
    public void append(T item) {
        int index = _items.size();
        _items.add(item);
        notifyListeners(new ListChange<>(ListChangeType.ADDED, index, Optional.of(item)));
    }

    /**
     * 插入项目（添加到末尾）
     * 注：此实现简化为追加到末尾，不支持任意位置插入
     */
    public void insert(long index, T item) {
        // 简化实现：添加到末尾
        int insertIndex = _items.size();
        _items.add(item);
        notifyListeners(new ListChange<>(ListChangeType.ADDED, insertIndex, Optional.of(item)));
    }

    /**
     * 移除项目
     */
    public void remove(long index) {
        if (index < 0 || index >= _items.size()) {
            throw new IndexOutOfBoundsException("Index: " + index + ", Size: " + _items.size());
        }
        T item = _items.remove((int) index);
        notifyListeners(new ListChange<>(ListChangeType.REMOVED, index, Optional.of(item)));
    }

    /**
     * 清空列表
     */
    public void clear() {
        _items.clear();
        notifyListeners(new ListChange<>(ListChangeType.RESET, -1L, Optional.empty()));
    }

    /**
     * 获取所有项目
     */
    public ArrayList<T> items() {
        return _items;
    }

    /**
     * 添加监听器
     */
    public void addListener(ListListener<T> listener) {
        _listeners.add(listener);
    }

    /**
     * 移除监听器
     * 注：简化实现，未提供具体移除逻辑
     */
    public void removeListener(ListListener<T> listener) {
        // 简化实现：暂不提供具体移除逻辑
        _listeners.remove(listener);
    }

    private void notifyListeners(ListChange<T> change) {
        for (ListListener<T> listener : _listeners) {
            listener.onChanged(change);
        }
    }
}

/**
 * 列表变更类型枚举
 */
enum ListChangeType {
    ADDED,
    REMOVED,
    UPDATED,
    RESET
}

/**
 * 列表变更事件
 * @param <T> 元素类型
 */
class ListChange<T> {
    public final ListChangeType type;
    public final long index;
    public final Optional<T> item;

    public ListChange(ListChangeType type, long index, Optional<T> item) {
        this.type = type;
        this.index = index;
        this.item = item;
    }
}

/**
 * 列表监听器接口
 * @param <T> 元素类型
 */
interface ListListener<T> {
    void onChanged(ListChange<T> change);
}

