/**
 * Draws an NRGBA source image onto an RGBA destination image within a specified rectangle.
 * Performs alpha blending: src is premultiplied, dst is not; result is stored in dst (premultiplied).
 *
 * @param dst  The destination RGBA image with its pixel data and bounds
 * @param r    The rectangle in destination coordinates to draw into
 * @param src  The source NRGBA image with its pixel data and bounds
 * @param sp   The top-left source point (in source coordinates) to start drawing from
 * @return     A tuple containing the modified dst and the drawn rectangle r
 */
public static class DrawResult {
    public final RGBA dst;
    public final Rectangle r;
    public DrawResult(RGBA dst, Rectangle r) {
        this.dst = dst;
        this.r = r;
    }
}

public static DrawResult drawNRGBASrc(RGBA dst, Rectangle r, NRGBA src, Point sp) {
    int i0 = (r.min.x - dst.rect.min.x) * 4;
    int i1 = (r.max.x - dst.rect.min.x) * 4;
    int si0 = (sp.x - src.rect.min.x) * 4;
    int yMax = r.max.y - dst.rect.min.y;

    int y = r.min.y - dst.rect.min.y;
    int sy = sp.y - src.rect.min.y;
    byte[] dpix = dst.pix;
    byte[] spix = src.pix;

    while (y != yMax) {
        int dpis = y * dst.stride;
        int spis = sy * src.stride;
        int i = i0;
        int si = si0;
        while (i < i1) {
            // Load source alpha (unpremultiplied), promote to UInt32 for precision
            int sa = (spix[spis + si + 3] & 0xFF) * 0x101; // scale to 16-bit range
            int sr = (spix[spis + si + 0] & 0xFF) * sa / 0xFF;
            int sg = (spix[spis + si + 1] & 0xFF) * sa / 0xFF;
            int sb = (spix[spis + si + 2] & 0xFF) * sa / 0xFF;

            dpix[dpis + i + 0] = (byte) (sr >> 8);
            dpix[dpis + i + 1] = (byte) (sg >> 8);
            dpix[dpis + i + 2] = (byte) (sb >> 8);
            dpix[dpis + i + 3] = (byte) (sa >> 8);

            i += 4;
            si += 4;
        }
        y++;
        sy++;
    }

    return new DrawResult(dst, r);
}

