public class IntegerTupleResponseBuilder implements ResponseBuilder<Pair<Long, Long>> {
    @Override
    public Pair<Long, Long> build(RedisMessage message) throws RedisException {
        if (message instanceof ArraysRedisMessage arraysMessage) {
            if (arraysMessage.isNull()) {
                throw new RedisException("Incompatible type, Nil/Null message is not the expect type");
            }

            Optional<List<RedisMessage>> childrenOpt = arraysMessage.getValue();
            if (childrenOpt.isPresent()) {
                List<RedisMessage> children = childrenOpt.get();
                if (children.size() != 2) {
                    throw new RedisException(
                        "Incompatible type, wrong size of ArraysRedisMessage, expect 2 but " + children.size()
                    );
                }

                long key = -1L;
                RedisMessage firstMessage = ResponseBuilderHelper.getRedisMessageOrThrow(
                    children.get(0), RedisMessageType.INTEGERS
                );
                if (firstMessage instanceof IntegerRedisMessage keyMessage) {
                    key = keyMessage.getValue();
                } else {
                    throw new RedisException(
                        "Incompatible type, expected first message's type: " + RedisMessageType.INTEGERS
                            + ", but " + firstMessage.getType()
                    );
                }

                long value = -1L;
                RedisMessage secondMessage = ResponseBuilderHelper.getRedisMessageOrThrow(
                    children.get(1), RedisMessageType.INTEGERS
                );
                if (secondMessage instanceof IntegerRedisMessage valueMessage) {
                    value = valueMessage.getValue();
                } else {
                    throw new RedisException(
                        "Incompatible type, expected second message's type: " + RedisMessageType.INTEGERS
                            + ", but " + secondMessage.getType()
                    );
                }

                return new Pair<>(key, value);
            } else {
                throw new RedisException("Incompatible type, nil arrays is not the expect type");
            }
        } else if (message instanceof ErrorRedisMessage errorMessage) {
            throw new RedisException(errorMessage.getValue());
        }

        throw new RedisException("Incompatible type, " + message.getType() + " is not the expect type");
    }

    // Simple immutable Pair class for Java compatibility (assuming no external Pair available)
    public static class Pair<T, U> {
        public final T first;
        public final U second;

        public Pair(T first, U second) {
            this.first = first;
            this.second = second;
        }
    }
}

