import java.time.Instant;
import java.time.Duration;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.concurrent.atomic.AtomicLong;

public class AdaptiveBatchingMailbox implements Mailbox, BatchDequeueSemantics {
    private final BatchingMailbox innerMailbox;
    private final long minBatchSize;
    private final long maxBatchSize;
    private final AtomicLong currentBatchSize;
    private final AtomicLong avgProcessingTime;
    private final Duration targetLatency;
    private final AtomicLong adjustmentCounter;

    public AdaptiveBatchingMailbox(long minBatchSize, long maxBatchSize,
                                   Duration batchTimeout, Duration targetLatency) {
        this.minBatchSize = minBatchSize;
        this.maxBatchSize = maxBatchSize;
        this.currentBatchSize = new AtomicLong(minBatchSize);
        this.targetLatency = targetLatency;
        this.avgProcessingTime = new AtomicLong(0);
        this.adjustmentCounter = new AtomicLong(0);

        // 使用当前批次大小创建内部邮箱
        this.innerMailbox = new BatchingMailbox(minBatchSize, batchTimeout);
    }

    @Override
    public boolean enqueue(Envelope envelope) {
        return innerMailbox.enqueue(envelope);
    }

    @Override
    public Optional<Envelope> dequeue() {
        return innerMailbox.dequeue();
    }

    @Override
    public List<Envelope> processBatch() {
        long startTime = getCurrentTimeNanos();
        List<Envelope> batch = innerMailbox.processBatch();

        if (!batch.isEmpty()) {
            long endTime = getCurrentTimeNanos();
            long processingTime = endTime - startTime;

            updateAverageProcessingTime(processingTime);
            adjustBatchSize(processingTime);
        }

        return batch;
    }

    private void updateAverageProcessingTime(long processingTime) {
        long currentAvg = avgProcessingTime.get();
        long newAvg = (currentAvg == 0) ? processingTime : (currentAvg * 9 + processingTime) / 10;
        avgProcessingTime.set(newAvg);
    }

    private void adjustBatchSize(long processingTime) {
        long adjustmentCount = adjustmentCounter.getAndIncrement();

        // 每10次处理后调整一次批次大小
        if (adjustmentCount % 10 != 0) {
            return;
        }

        long currentAvg = avgProcessingTime.get();
        long targetNanos = targetLatency.toMillis() * 1_000_000L;
        long currentSize = currentBatchSize.get();

        if (currentAvg > targetNanos) {
            // 处理时间过长，减小批次
            long newSize = Math.max(minBatchSize, currentSize * 8 / 10);
            if (newSize != currentSize) {
                currentBatchSize.set(newSize);
                System.out.println("减小批次大小: " + currentSize + " -> " + newSize);
            }
        } else if (currentAvg < targetNanos / 2) {
            // 处理时间很短，增大批次
            long newSize = Math.min(maxBatchSize, currentSize * 12 / 10);
            if (newSize != currentSize) {
                currentBatchSize.set(newSize);
                System.out.println("增大批次大小: " + currentSize + " -> " + newSize);
            }
        }
    }

    private long getCurrentTimeNanos() {
        return Instant.now().toEpochMilli() * 1_000_000L;
    }

    @Override
    public boolean isEmpty() {
        return innerMailbox.isEmpty();
    }

    @Override
    public long size() {
        return innerMailbox.size();
    }

    @Override
    public void clear() {
        innerMailbox.clear();
    }

    @Override
    public boolean isClosed() {
        return innerMailbox.isClosed();
    }

    @Override
    public void close() {
        innerMailbox.close();
    }

    public long getCurrentBatchSize() {
        return currentBatchSize.get();
    }

    public long getAverageProcessingTime() {
        return avgProcessingTime.get();
    }

    public Duration getTargetLatency() {
        return targetLatency;
    }

    // BatchDequeueSemantics
    @Override
    public List<Envelope> dequeueBatch(int max) {
        return innerMailbox.dequeueBatch(max);
    }
}

