class AfterDoctypeNameState extends TokeniserState {
    @Override
    protected void read(Tokeniser tker, CharacterReader r) {
        if (r.isEmpty()) {
            tker.eofError(this);
            tker.doctypePending.forceQuirks = true;
            tker.emitDoctypePending();
            tker.transition(Data);
            return;
        }
        if (r.matchesAny('\t', '\n', '\r', '\f', ' ')) {
            r.advance(); // ignore whitespace
        } else if (r.matches('>')) {
            tker.emitDoctypePending();
            tker.advanceTransition(Data);
        } else if (r.matchConsumeIgnoreCase(DocumentType.PUBLIC_KEY)) {
            tker.doctypePending.pubSysKey = DocumentType.PUBLIC_KEY;
            tker.transition(AfterDoctypePublicKeyword.class);
        } else if (r.matchConsumeIgnoreCase(DocumentType.SYSTEM_KEY)) {
            tker.doctypePending.pubSysKey = DocumentType.SYSTEM_KEY;
            tker.transition(AfterDoctypeSystemKeyword.class);
        } else {
            tker.error(this);
            tker.doctypePending.forceQuirks = true;
            tker.advanceTransition(BogusDoctype.class);
        }
    }
}

