    byte xorSum = 0;
    initBitInput();

    int cpLength = Math.min(MAX_SIZE, codeSize);
    for (long i = 0; i < cpLength; i++) {
        inBuf[(int)i] |= code[(int)i];
    }
    for (long i = 1; i < codeSize; i++) {
