public class EventSender {
    public static void sendEvent(JoyContext ctx, String eventId, ByteBuffer data) {
        // Get the event emitter from the context
        JoyEventEmitter emitter = ctx.eventEmitter();
        // Create an SSE event builder
        JoySseBuilder eventBuilder = new JoySseBuilder();
        eventBuilder.id(eventId);
        // Convert ByteBuffer to UTF-8 string and set as event data
        eventBuilder.data(new String(data.array(), StandardCharsets.UTF_8));
        // Send the constructed event
        emitter.sendEvent(eventBuilder);
    }
}

