public class LogSumExp {
    public static double fLogSumExp(double[] s) {
        double fMaxVal = fMax(s);
        if (Double.isInfinite(fMaxVal)) {
            return fMaxVal;
        }
        double lse = 0.0;
        for (double val : s) {
            lse += Math.exp(val - fMaxVal);
        }
        return Math.log(lse) + fMaxVal;
    }

    // Helper function to compute maximum value of a double array
    private static double fMax(double[] arr) {
        if (arr == null || arr.length == 0) {
            throw new IllegalArgumentException("Array must not be null or empty");
        }
        double max = arr[0];
        for (int i = 1; i < arr.length; i++) {
            if (arr[i] > max) {
                max = arr[i];
            }
        }
        return max;
    }

    // Example main method for testing
    public static void main(String[] args) {
        double[] testArray = {1.0, 2.0, 3.0};
        System.out.println(fLogSumExp(testArray)); // Expected: ~3.4076...
    }
}

