     *
     * @param eps 邻域半径
     * @param minSamples 核心点所需的最小邻居数
     */
    public DBSCAN(double eps, int minSamples) {
        this.eps = eps;
        this.minSamples = minSamples;
    }

    public DBSCAN() {
        this(0.5, 5);
    }

    private double euclideanDistance(double[] a, double[] b) {
        double sum = 0.0;
        for (int i = 0; i < a.length; i++) {
            double diff = a[i] - b[i];
            sum += diff * diff;
        }
        return Math.sqrt(sum);
    }

    /**
     * 找出点的所有邻居
     */
    private int[] regionQuery(double[][] X, int pointIdx) {
        List<Integer> neighbors = new ArrayList<>();
        double[] point = X[pointIdx];

        for (int i = 0; i < X.length; i++) {
            if (euclideanDistance(point, X[i]) <= eps) {
                neighbors.add(i);
            }
        }

        int[] result = new int[neighbors.size()];
        for (int i = 0; i < neighbors.size(); i++) {
            result[i] = neighbors.get(i);
        }
        return result;
    }

    /**
     * 扩展聚类
     */
    private void expandCluster(double[][] X, int[] labels, int pointIdx,
                               int[] neighbors, int clusterId, boolean[] visited) {
        labels[pointIdx] = clusterId;

        List<Integer> neighborList = new ArrayList<>();
        for (int n : neighbors) {
            neighborList.add(n);
        }

        int i = 0;
        while (i < neighborList.size()) {
            int neighborIdx = neighborList.get(i);

            if (!visited[neighborIdx]) {
                visited[neighborIdx] = true;
                int[] newNeighbors = regionQuery(X, neighborIdx);

                if (newNeighbors.length >= minSamples) {
                    for (int nn : newNeighbors) {
                        boolean found = false;
                        for (int j = 0; j < neighborList.size(); j++) {
                            if (neighborList.get(j) == nn) {
                                found = true;
                                break;
                            }
                        }
                        if (!found) {
                            neighborList.add(nn);
                        }
                    }
                }
            }

            if (labels[neighborIdx] == -1) {
                labels[neighborIdx] = clusterId;
            }

            i++;
        }
    }

    /**
     * 拟合DBSCAN
     */
    public void fit(double[][] X) {
        int n = X.length;
        labels_ = new int[n];
        Arrays.fill(labels_, -1);  // -1表示噪声
        boolean[] visited = new boolean[n];
        int clusterId = 0;

        List<Integer> coreList = new ArrayList<>();

        for (int i = 0; i < n; i++) {
            if (visited[i]) {
                continue;
            }

            visited[i] = true;
            int[] neighbors = regionQuery(X, i);

            if (neighbors.length < minSamples) {
                // 标记为噪声（可能后续被加入某个聚类）
                labels_[i] = -1;
            } else {
                // 核心点，开始新聚类
                coreList.add(i);
                expandCluster(X, labels_, i, neighbors, clusterId, visited);
                clusterId++;
            }
        }

        coreIndices_ = new int[coreList.size()];
        for (int i = 0; i < coreList.size(); i++) {
            coreIndices_[i] = coreList.get(i);
        }
    }

    /**
     * 拟合并返回标签
     */
    public int[] fitPredict(double[][] X) {
        fit(X);
        return labels_;
    }

    /**
     * 获取标签
     */
    public int[] getLabels() {
        return labels_;
    }

    /**
     * 获取核心样本索引
     */
    public int[] getCoreIndices() {
        return coreIndices_;
    }
}

