            toString(userContext, userContext == null),
            toString(callback, callback == null, "IMqttActionListener")
        }
    );

    comms.setNetworkModules(createNetworkModules(serverURI, options));
    comms.setReconnectCallback(new MqttReconnectCallback(this, automaticReconnect));

    // Insert our own callback to iterate through the URIs till the connect succeeds
    MqttToken userToken = new MqttToken(getClientId());
    ConnectActionListener connectActionListener = new ConnectActionListener(
        this,
        persistence,
        comms,
        options,
        userToken,
        userContext,
        callback,
        reconnecting
    );
    userToken.setActionCallback(connectActionListener);
    userToken.setUserContext(this);

