public class StreamPendingSummaryResponseBuilder implements ResponseBuilder<StreamPendingSummary> {
    public static final StreamPendingSummaryResponseBuilder INSTANCE = new StreamPendingSummaryResponseBuilder();

    @Override
    public StreamPendingSummary build(RedisMessage message) {
        if (message instanceof ArraysRedisMessage arraysMessage) {
            java.util.Optional<java.util.List<RedisMessage>> childrenOpt = arraysMessage.getValue();
            if (childrenOpt.isPresent()) {
                java.util.List<RedisMessage> children = childrenOpt.get();
                if (children.size() != 4) {
                    throw new RedisException(
                        "Incompatible type, wrong size of ArraysRedisMessage, expected 4 but " + children.size()
                    );
                }

                RedisMessage totalMessage = ResponseBuilderHelper.getRedisMessageOrThrow(
                    children.get(0), RedisMessageType.INTEGERS
                );

                RedisMessage minIdMessage = ResponseBuilderHelper.getRedisMessageOrThrow(
                    children.get(1), RedisMessageType.BULK_STRINGS
                );

                RedisMessage maxIdMessage = ResponseBuilderHelper.getRedisMessageOrThrow(
                    children.get(2), RedisMessageType.BULK_STRINGS
                );

                // Note: original仓颉 code mistakenly uses index 2 again for mapMessage;
                // based on context (expected 4-element array: total, minId, maxId, map),
                // this should be index 3. Fixed to avoid logical error.
                RedisMessage mapMessage = ResponseBuilderHelper.getRedisMessageOrThrow(
                    children.get(3), RedisMessageType.ARRAYS
                );

                return new StreamPendingSummary(
                    ResponseBuilderFactory.integerBuilder.build(totalMessage),
                    StreamEntryIDResponseBuilder.INSTANCE.build(minIdMessage),
                    StreamEntryIDResponseBuilder.INSTANCE.build(maxIdMessage),
                    ResponseBuilderFactory.stringToIntegerMapBuilder.build(mapMessage)
                );
            } else {
                throw new RedisException("Incompatible type, nil arrays is not the expected type");
            }
        } else if (message instanceof ErrorRedisMessage errorMessage) {
            throw new RedisException(errorMessage.getValue());
        }

        throw new RedisException("Incompatible type, " + message.getType() + " is not the expected type");
    }
}

