public interface McpSession extends AutoCloseable {
    /**
     * 发送 JSON-RPC 请求并等待响应
     *
     * @param method 方法名称
     * @param requestParams 请求参数
     * @param <T> 响应类型，需支持 JSON 反序列化
     * @return 类型 T 的响应
     */
    <T extends JsonDeserializable<T>> T sendRequest(String method, JsonSerializable requestParams);

    /**
     * 发送 JSON-RPC 通知而不等待响应
     *
     * @param method 通知方法名称
     * @param params 通知参数
     */
    void sendNotification(String method, JsonSerializable params);

    /**
     * 发送 JSON-RPC 通知而不等待响应（无参数重载）
     *
     * @param method 通知方法名称
     */
    default void sendNotification(String method) {
        sendNotification(method, null);
    }

    /**
     * 为通知方法添加消费者
     *
     * @param method 通知方法名称
     * @param consumer 处理通知字节的消费者函数
     */
    void addNotificationConsumer(String method, java.util.function.Consumer<byte[]> consumer);
}

