        for (i in 0..a.size) {
            sum += pow(abs(a[i] - b[i]), p)
        }
        return pow(sum, 1.0 / p)
    }

    /**
     * 切比雪夫距离
     */
    public static func chebyshev(a: Array<Float64>, b: Array<Float64>): Float64 {
        var maxDiff = 0.0
        for (i in 0..a.size) {
            let diff = abs(a[i] - b[i])
            if (diff > maxDiff) {
                maxDiff = diff
            }
        }
        return maxDiff
    }

    /**
     * 汉明距离（用于二进制向量）
     */
    public static func hamming(a: Array<Int64>, b: Array<Int64>): Float64 {
        var diff: Int64 = 0
        for (i in 0..a.size) {
            if (a[i] != b[i]) {
                diff += 1
            }
        }
        return Float64(diff) / Float64(a.size)
    }

    /**
     * 杰卡德距离
     */
    public static func jaccard(a: Array<Int64>, b: Array<Int64>): Float64 {
        var intersection: Int64 = 0
        var union: Int64 = 0

        for (i in 0..a.size) {
            if (a[i] == 1 || b[i] == 1) {
                union += 1
                if (a[i] == 1 && b[i] == 1) {
                    intersection += 1
                }
            }
        }

        if (union == 0) {
            return 0.0
        }
        return 1.0 - Float64(intersection) / Float64(union)
    }
}

