private ActiveMQMessage createActiveMQMessage(MessageDispatch md) {
    if (md.message != null) {
        Object messageCopy = md.message.copy();
        if (messageCopy instanceof ActiveMQMessage) {
            ActiveMQMessage m = (ActiveMQMessage) messageCopy;
            // 消息通过MessageTransformer进行转换
            if (messageTransformer != null) {
                CJMSMessage transformerMessage = messageTransformer.consumerTransform(session, this, m);
                m = ActiveMQMessageTransformation.transformMessage(transformerMessage, session.getConnection());
            }
            if (session.isClientAcknowledge()) {
                // 给消息设置手动确认回调
                m.setAcknowledgeCallback(new ClientAcknowledgeCallback(this));
            } else if (session.isIndividualAcknowledge()) {
                m.setAcknowledgeCallback(new IndividualAcknowledgeCallback(this, md));
            }
            return m;
        }
    }
    return null;
}

