public class DeflaterInputStream extends CompressInputStream {
    private static final int DEF_MEM_LEVEL = 8;
    private static final int Z_DEFAULT_STRATEGY = 0;

    public DeflaterInputStream(InputStream in_, long bufferSize, long level, int memLevel, int strategy) {
        super(in_, new Deflater(), (int) bufferSize, true, true);
        int lev = (level < 0 || level > 9) ? 6 : (int) level;
        int mem = (memLevel < 1 || memLevel > 9) ? DEF_MEM_LEVEL : memLevel;
        int str = (strategy < 0 || strategy > 4) ? Z_DEFAULT_STRATEGY : strategy;
        this.deflater.deflateInit2(lev, -15, mem, str);
    }

