public class GeoRadiusResponseBuilder implements ResponseBuilder<GeoRadiusResponse> {
    @Override
    public GeoRadiusResponse build(RedisMessage message) {
        if (message instanceof ArraysRedisMessage arraysMessage) {
            List<RedisMessage> children = arraysMessage.getValue();
            if (children != null && !children.isEmpty()) {
                RedisMessage memberMsg = ResponseBuilderHelper.getRedisMessageOrThrow(
                    children.get(0),
                    RedisMessageType.BULK_STRINGS
                );

                GeoRadiusResponse response = new GeoRadiusResponse(
                    ResponseBuilderFactory.stringBuilder.build(memberMsg)
                );

                // Process remaining items: index 1 onwards
                for (int i = 1; i < children.size(); i++) {
                    RedisMessage item = children.get(i).getOrThrow();
                    if (item instanceof ArraysRedisMessage arrayItem) {
                        response.setCoordinate(new GeoCoordinateResponseBuilder().build(arrayItem));
                    } else if (item instanceof IntegerRedisMessage integerItem) {
                        response.setRawScore(ResponseBuilderFactory.integerBuilder.build(integerItem));
                    } else {
                        response.setDistance(ResponseBuilderFactory.doubleBuilder.build(item));
                    }
                }
                return response;
            } else {
                throw new RedisException("Incompatible type, nil arrays is not the expected type");
            }
        } else if (message instanceof ErrorRedisMessage errorMessage) {
            throw new RedisException(errorMessage.getValue());
        }

        throw new RedisException("Unsupported message type: " + message.getType());
    }
}

