    private static native void cblas_zgemv(int order, int trans, int m, int n,
                                           double[] alpha, double[] a, int lda,
                                           double[] x, int incx, double[] beta,
                                           double[] y, int incy);

    // Constants for CBLAS
    private static final int CblasColMajor = 101;
    private static final int CblasNoTrans = 111;

    /**
     * Performs matrix-vector multiplication: y = alpha * A * x + beta * y
     * For complex64 (double precision complex), column-major storage.
     * This implementation assumes Complex64 is represented as interleaved double array:
     * [re0, im0, re1, im1, ...]
     */
    public static double[] cj_zgemv(double[] a, int rows, int cols, double[] x) {
        if (cols != x.length / 2) {
            throw new IllegalArgumentException("Matrix-vector multiply: dimension mismatch");
        }
        int m = rows;
        int n = cols;
        int lda = m; // leading dimension of matrix A (column-major)

        // alpha = 1.0 + 0.0i, beta = 0.0 + 0.0i
        double[] alpha = {1.0, 0.0};
        double[] beta = {0.0, 0.0};

        // Allocate output vector y of size m (complex numbers => 2*m doubles)
        double[] y = new double[2 * m];

        // Call native zgemv: y = alpha * A * x + beta * y
        // Matrix A is stored column-major, interleaved complex
        cblas_zgemv(CblasColMajor, CblasNoTrans, m, n, alpha, a, lda, x, 1, beta, y, 1);

        return y;
    }

