    if (a.getCols() != x.size()) {
        throw IllegalArgumentException("Matrix-vector multiply: dimension mismatch")
    }
    let m = a.getRows()
    let n = a.getCols()
    let lda = m
    var alpha: CPointer<Unit> = unsafe {malloc(UIntNative(16))}
    var beta: CPointer<Unit> = unsafe {malloc(UIntNative(16))}
    Complex64.write(alpha, Complex64(1.0, 0.0), 0)
    Complex64.write(beta, Complex64(0.0, 0.0), 0)
    let y = empty<Complex64>(m)
    unsafe { cblas_zgemv(CblasColMajor, CblasNoTrans, m, n, alpha, a.ptr, lda,
                         x.ptr, 1, beta, y.ptr, 1)}
    unsafe { free(alpha) }
    unsafe { free(beta) }
    return y
}

