    public void absoluteTest() {
        Money m1 = new Money(123, "WST");
        Money m2 = new Money(132.12, "SCR");
        Money m3 = new Money(0, "LAK");
        Money m4 = new Money(0.0, "GTQ");
        Money m5 = new Money(-12, "IMP");
        Money m6 = new Money(-1.435123, "CAD");

        m1.absolute();
        m2.absolute();
        m3.absolute();
        m4.absolute();
        m5.absolute();
        m6.absolute();

        // Expected results after absolute()
        assert m1.getAmount() == 123 : "m1.amount expected 123";
        assert m2.getAmount() == 13212 : "m2.amount expected 13212";
        assert m3.getAmount() == 0 : "m3.amount expected 0";
        assert m4.getAmount() == 0 : "m4.amount expected 0";
        assert m5.getAmount() == 12 : "m5.amount expected 12";
        assert m6.getAmount() == 144 : "m6.amount expected 144";
    }

    // Test case for negative() method
    public void negativeTest() {
        Money m1 = new Money(123, "WST");
        Money m2 = new Money(132.12, "SCR");
        Money m3 = new Money(0, "LAK");
        Money m4 = new Money(0.0, "GTQ");
