        assert m3.getAmount() == 0 : "m3.amount expected 0";
        assert m4.getAmount() == 0 : "m4.amount expected 0";
        assert m5.getAmount() == 12 : "m5.amount expected 12";
        assert m6.getAmount() == 144 : "m6.amount expected 144";
    }

    // Main method to run tests (optional; assumes JUnit not required)
    public static void main(String[] args) {
        OperationOnSelf test = new OperationOnSelf();
        test.absoluteTest();
        test.negativeTest();
        System.out.println("All tests passed.");
    }
