public void renewClusterSlots(ClientTcpEndpoint clientTcpEndpointVal) {
    if (rediscoverLock.tryLock()) {
        try {
            // First, if pool is available, use pool renew.
            if (clientTcpEndpointVal != null) {
                try {
                    discoverClusterSlots(clientTcpEndpointVal);
                    return;
                } catch (RedisException ex) {
                    // try nodes from all pools
                }
            }

            // Then, we use startNodes to try, as long as startNodes is available,
            // whether it is vip, domain, or physical ip, it will succeed.
            if (!startNodes.isEmpty()) {
                for (String node : startNodes) {
                    ClientTcpEndpoint tcpEndPoint = null;
                    try {
                        ClientTcpEndpoint endPoint = this.buildClusterEndPoint(node, subscribeMode);
                        tcpEndPoint = endPoint;
                        discoverClusterSlots(endPoint);
                        return;
                    } catch (Exception ex) {
                        // try next nodes
                    } finally {
                        if (tcpEndPoint != null) {
                            tcpEndPoint.stop();
                        }
                    }
                }
            }

            // Finally, we go back to the ShuffledNodesPool and try the remaining physical nodes.
            for (ClientTcpEndpoint pool : getShuffledNodesPool()) {
                try {
                    if (startNodes.contains(HostAndPort.toHostAndPort(pool.getRemoteAddress()))) {
                        continue;
                    }
                    discoverClusterSlots(pool);
                    return;
                } catch (Exception ex) {
                    // try next nodes
                }
            }
        } finally {
            rediscoverLock.unlock();
        }
    }
}

