public static YCC convertToYCC440(YCbCr ycbcr, YCC p) {
    int off = 0;
    byte[] pix = p.pix;
    byte[] Y = ycbcr.y;
    byte[] Cb = ycbcr.cb;
    byte[] Cr = ycbcr.cr;
    for (int y = 0; y < ycbcr.rect.dy(); y++) {
        int yy = y * ycbcr.yStride;
        int cy = (y / 2) * ycbcr.cStride;
        for (int x = 0; x < ycbcr.rect.dx(); x++) {
            int ci = cy + x;
            pix[off + 0] = Y[yy + x];
            pix[off + 1] = Cb[ci];
            pix[off + 2] = Cr[ci];
            off += 3;
        }
    }
    return p;
