func convertToYCC440(ycbcr: YCbCr, p: YCC): YCC {
    var off = 0
    let pix = p.pix
    let Y = ycbcr.y
    let Cb = ycbcr.cb
    let Cr = ycbcr.cr
    for (y in 0..ycbcr.rect.dy()) {
        let yy = y * ycbcr.yStride
        let cy = (y / 2) * ycbcr.cStride
        for (x in 0..ycbcr.rect.dx()) {
            let ci = cy + x
            pix[off + 0] = Y[yy + x]
            pix[off + 1] = Cb[ci]
            pix[off + 2] = Cr[ci]
            off += 3
        }
    }
    return p
}

