public void clearMessagesInProgress() {
    if (inProgressClearRequiredFlag.get() > 0) {
        synchronized (unconsumedMessages.getMutex()) {
            if (inProgressClearRequiredFlag.get() > 0) {
                logger.debug("{} clearing unconsumed list ({}) on transport interrupt",
                        consumerId, unconsumedMessages.size());
                // 确保未消费的消息可以被发送给其它的消费者
                LinkedList<MessageDispatch> list = unconsumedMessages.removeAll();
                if (!this.info.isBrowser()) {
                    for (MessageDispatch old : list) {
                        if (old.getMessage().isPresent()) {
                            Message message = old.getMessage().get();
                            session.connection.rollbackDuplicate(this, message);
                        }
                    }
                }
                session.connection.transportInterruptionProcessingComplete();
                inProgressClearRequiredFlag.set(0);

                unconsumedMessages.getCondition().notifyAll();
            }
        }
        clearDeliveredMessages();
    }
}

