public static HttpResponseHeaderCheckResult checkResponseHeader(HttpResponse response, Long bodySize) {
    int status = response.getStatus();
    HttpHeaders headers = response.getHeaders();

    if (logger.isEnabled(LogLevel.DEBUG)) {
        httpLogDebug(logger,
            "[HttpEngineConn1#checkResponse] raw status line: " + response.getVersion() + " " + response.getStatus() + " " + response.getPhrase()
        );
        httpLogDebug(logger, "[HttpEngineConn1#checkResponse] raw response headers: " + headers.toString());
    }

    // A server that sends a 100 (Continue) response MUST ultimately send a final status code, once it receives and processes the request content,
    // unless the connection is closed prematurely.
    // RFC 9110 10.1.1.
    if (status == HttpStatusCode.STATUS_CONTINUE) {
        response.setStatus(HttpStatusCode.STATUS_INTERNAL_SERVER_ERROR);
        response.setHeaders(new HttpHeaders());
        byte[] errorBytes = "Internal Server Error: invalid status code".getBytes(StandardCharsets.UTF_8);
        response.setBody(new HttpRawBody(errorBytes));
        response.setBodySize((long) errorBytes.length);
        httpLogInfo(logger, "[HttpEngineConn1#checkResponse] The final status code cannot be 100");
    }

    if (Boolean.TRUE.equals(response.getRequest() != null ? response.getRequest().isClose() : null) && !response.isClose()) {
        headers.add("connection", "close");
    }
    checkConnection(headers);

    String dateStr = getRFC1123String(dateArr).toString();
    headers.set("date", dateStr);

    // check the logic of "content-length" and "transfer-encoding" in response header
    HttpResponseHeaderCheckResult clTeResult = checkClAndTe(headers);
    long contentLength = clTeResult.contentLength;
    boolean chunked = clTeResult.chunked;
    if (chunked) {
        checkTrailerInHeader(headers, false);
    }

    if (HTTP1_0.equals(response.getVersion())) {
        httpLogWarn(logger, "[HttpEngineConn1#checkResponse] HTTP/1.0 response is not supported");
        if (chunked) {
            throw new HttpException("The body cannot be sent in chunked mode in HTTP/1.0.");
        }
        response.setVersion(HTTP1_1);
    }

    // Any response to a HEAD request and any response with a 1xx (Informational), 204 (No Content), or 304 (Not Modified) status code
    // is always terminated by the first empty line after the header fields, regardless of the header fields present in the message,
    // and thus cannot contain a message body or trailer section.
    // RFC 9112 6.3.1
    boolean statusWithoutContent = status / 100 == 1 || status == HttpStatusCode.STATUS_NO_CONTENT || status == HttpStatusCode.STATUS_NOT_MODIFIED;
    if (statusWithoutContent) {
        if (bodySize != null) {
            if (chunked && bodySize > 0) {
                throw new HttpException("The body is not allowed in this scenario.");
            }
        }
        response.setBody(HttpEmptyBody.INSTANCE);
        httpLogInfo(logger, "[HttpEngineConn1#checkResponse] the body should be empty");
        contentLength = 0L;
        headers.set("content-length", "0");
    }

    if (logger.isEnabled(LogLevel.DEBUG)) {
        httpLogDebug(logger,
            "[HttpEngineConn1#checkResponse] status line: " + response.getVersion() + " " + response.getStatus() + " " + response.getPhrase()
        );
        httpLogDebug(logger, "[HttpEngineConn1#checkResponse] response headers: " + headers.toString());
    }
    return new HttpResponseHeaderCheckResult(contentLength, chunked);
}

