public static boolean drotTest(NFloat64 nFloat64) {
    for (DoubleTwoVectorCase c : doubleTwoVectorCases) {
        for (DrotCase kind : c.drotCases) {
            dCopyTwoTmp(c.x, c.xTmp, c.y, c.yTmp);
            if (c.exception) {
                try {
                    nFloat64.drot(c.n, c.xTmp, c.incx, c.yTmp, c.incy, kind.c, kind.s);
                    throw new RuntimeException(c.name + " should panic and does not");
                } catch (Exception ignored) {
                    // Expected exception — continue to next case
                    continue;
                }
            }
            nFloat64.drot(c.n, c.xTmp, c.incx, c.yTmp, c.incy, kind.c, kind.s);
            if (!dSliceTolEqual(c.xTmp, kind.xAns)) {
                throw new RuntimeException("drot: x mismatch " + c.name + ": expected " + kind.xAns + ", found " + c.xTmp);
            }
            if (!dSliceTolEqual(c.yTmp, kind.yAns)) {
                throw new RuntimeException("drot: y mismatch " + c.name + ": expected " + kind.yAns + ", found " + c.yTmp);
            }
        }
    }
    return true;
}

