public static boolean putBreak(EmitterT emitter) {
    if (emitter.bufferPos + 5 >= emitter.buffer.length && !emitterFlush(emitter)) {
        return false;
    }
    switch (emitter.lineBreak) {
        case BreakT_LN_BREAK:
            emitter.buffer[emitter.bufferPos] = (byte) 0x0A;
            emitter.bufferPos++;
            break;
        default:
            throw new RuntimeException("unknown line break setting");
    }
    emitter.column = 0;
    emitter.line++;
    return true;
}

