public class ByteConverter {
    // ENDIAN == 2 means big-endian; otherwise little-endian
    private static final int ENDIAN = 2;

    public static long byteArrToUInt64(byte[] data) {
        if (data.length < 8) {
            throw new IllegalArgumentException("Array must have at least 8 bytes");
        }
        if (ENDIAN == 2) { // 大端序 保留
            return ((long)(data[0] & 0xFF) << 56) |
                   ((long)(data[1] & 0xFF) << 48) |
                   ((long)(data[2] & 0xFF) << 40) |
                   ((long)(data[3] & 0xFF) << 32) |
                   ((long)(data[4] & 0xFF) << 24) |
                   ((long)(data[5] & 0xFF) << 16) |
                   ((long)(data[6] & 0xFF) << 8)  |
                   ((long)(data[7] & 0xFF));
        } else { // 大端序->转小端序
            return ((long)(data[0] & 0xFF))        |
                   ((long)(data[1] & 0xFF) << 8)  |
                   ((long)(data[2] & 0xFF) << 16) |
                   ((long)(data[3] & 0xFF) << 24) |
                   ((long)(data[4] & 0xFF) << 32) |
                   ((long)(data[5] & 0xFF) << 40) |
                   ((long)(data[6] & 0xFF) << 48) |
                   ((long)(data[7] & 0xFF) << 56);
        }
    }
}

