public class BigMoneyOperationOnSelf {

    public static void absoluteTest() {
        BigMoney m1 = new BigMoney("12314315154123455555555554326546665789856566", "WST");
        BigMoney m2 = new BigMoney("1143142532567664765735735632.113422454325364634562", "SCR");
        BigMoney m3 = new BigMoney("0", "LAK");
        BigMoney m4 = new BigMoney("0.0", "GTQ");
        BigMoney m5 = new BigMoney("-142345345674578569753452442522", "IMP");
        BigMoney m6 = new BigMoney("-1.4245235647655555465243255624535123", "CAD");

        m1.absolute();
        m2.absolute();
        m3.absolute();
        m4.absolute();
        m5.absolute();
        m6.absolute();

        // Expected results after absolute()
        assert m1.getAmount().equals(new java.math.BigInteger("1231431515412345555555555432654666578985656600"));
        assert m2.getAmount().equals(new java.math.BigInteger("114314253256766476573573563211"));
        assert m3.getAmount().equals(java.math.BigInteger.ZERO);
        assert m4.getAmount().equals(java.math.BigInteger.ZERO);
        assert m5.getAmount().equals(new java.math.BigInteger("14234534567457856975345244252200"));
        assert m6.getAmount().equals(new java.math.BigInteger("142"));
    }

    public static void negativeTest() {
        BigMoney m1 = new BigMoney("12314315154123455555555554326546665789856566", "WST");
        BigMoney m2 = new BigMoney("1143142532567664765735735632.113422454325364634562", "SCR");
        BigMoney m3 = new BigMoney("0", "LAK");
        BigMoney m4 = new BigMoney("0.0", "GTQ");
        BigMoney m5 = new BigMoney("-142345345674578569753452442522", "IMP");
        BigMoney m6 = new BigMoney("-1.4245235647655555465243255624535123", "CAD");

        m1.negative();
        m2.negative();
        m3.negative();
        m4.negative();
        m5.negative();
        m6.negative();

        // Expected results after negative()
        assert m1.getAmount().equals(new java.math.BigInteger("-1231431515412345555555555432654666578985656600"));
        assert m2.getAmount().equals(new java.math.BigInteger("-114314253256766476573573563211"));
        assert m3.getAmount().equals(java.math.BigInteger.ZERO);
        assert m4.getAmount().equals(java.math.BigInteger.ZERO);
        assert m5.getAmount().equals(new java.math.BigInteger("14234534567457856975345244252200"));
        assert m6.getAmount().equals(new java.math.BigInteger("142"));
    }

    // Main method to run tests (optional, for standalone execution)
    public static void main(String[] args) {
        absoluteTest();
        negativeTest();
    }
